class Solution:
    def scoreBalance(self, s):
        vals = [ord(c) - 96 for c in s]
        total = sum(vals)
        if total % 2:
            return False
        half = total // 2
        run = 0
        for i in range(len(vals) - 1):
            run += vals[i]
            if run == half:
                return True
        return False

