var scoreBalance = function(s) {
    const vals = [];
    for (const c of s) vals.push(c.charCodeAt(0) - 96);
    const total = vals.reduce((a, b) => a + b, 0);
    if (total % 2) return false;
    const half = total / 2;
    let run = 0;
    for (let i = 0; i < vals.length - 1; i++) {
        run += vals[i];
        if (run === half) return true;
    }
    return false;
};
